class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert_into_bst(node, value):
    if node is None:
        return Node(value)
    if value < node.value:
        node.left = insert_into_bst(node.left, value)
    else:
        node.right = insert_into_bst(node.right, value)
    return node

def process_characters(sequence):
    root = None
    for char in sequence:
        lower_char = char.lower()
        root = insert_into_bst(root, lower_char)
    return root

# Example usage
sequence = ["A", "b", "C", "d", "E", "f"]
root = process_characters(sequence)
